{"content": "import { EventEmitter } from 'events';

const emitter = new EventEmitter();

export class DataProcessor {
  private handlers: Function[] = [];

  processStream(streamId: string) {
    const handler = (data: any) => {
      if (data.streamId === streamId) {
        this.transform(data);
      }
    };
    emitter.on('data', handler);
    // Never removes the listener
  }

  transform(data: any) {
    return data;
  }

  registerHandler(fn: Function) {
    this.handlers.push(fn);
  }
}
"}

Found the leak in `src/services/events.ts:14`. Every call to `processStream()` adds a new listener to the emitter but never removes it. Over time this accumulates unbounded listeners.

**Fix:** Store the handler reference so it can be removed when processing ends, or use `emitter.once()` if you only need it once. Also add a `cleanup()` method:

```ts
// Store reference for cleanup
private activeHandlers = new Map<string, Function>();

processStream(streamId: string) {
  const handler = (data: any) => {
    if (data.streamId === streamId) this.transform(data);
  };
  this.activeHandlers.set(streamId, handler);
  emitter.on('data', handler);
}

stopStream(streamId: string) {
  const handler = this.activeHandlers.get(streamId);
  if (handler) {
    emitter.removeListener('data', handler);
    this.activeHandlers.delete(streamId);
  }
}
