{"name": "write_file", "arguments": {"path": "src/middleware/rateLimit.ts", "content": "const requests = new Map<string, { count: number; resetAt: number }>();

// Clean up stale entries every 5 minutes
setInterval(() => {
  const now = Date.now();
  for (const [key, val] of requests) {
    if (now > val.resetAt) requests.delete(key);
  }
}, 300_000);

export function rateLimit(max = 60, windowMs = 60_000) {
  return (req: any, res: any, next: any) => {
    const ip = req.ip;
    const now = Date.now();
    const entry = requests.get(ip);

    if (!entry || now > entry.resetAt) {
      requests.set(ip, { count: 1, resetAt: now + windowMs });
      return next();
    }

    if (entry.count >= max) {
      const retry = Math.ceil((entry.resetAt - now) / 1000);
      res.set('Retry-After', String(retry));
      return res.status(429).json({ error: 'Too many requests', retryAfter: retry });
    }

    entry.count++;
    next();
  };
}"}}
